import { describe, it, expect } from "vitest";
import { nextGeneration } from "./game-of-life.js";

describe("Game of Life - Next Generation", () => {
  it("should return empty grid when given empty grid", () => {
    expect(nextGeneration([])).toEqual([]);
  });
  it("should kill a single live cell with no neighbors (underpopulation)", () => {
    expect(nextGeneration([[0, 0]])).toEqual([]);
  });
  it("should kill two adjacent cells each having only one neighbor (underpopulation)", () => {
    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
  });
  it("should keep alive a cell with exactly two neighbors (survival)", () => {
    // Three cells in a vertical line: center cell (1,1) has 2 neighbors → survives
    const result = nextGeneration([[0, 1], [1, 1], [2, 1]]);
    const sorted = [...result].sort((a, b) => a[0] - b[0] || a[1] - b[1]);
    expect(sorted).toEqual([[1, 0], [1, 1], [1, 2]]);
  });
  it.todo("should keep alive a cell with exactly three neighbors (survival)");
  it.todo("should kill a cell with more than three neighbors (overpopulation)");
  it.todo("should bring a dead cell to life when it has exactly three live neighbors (reproduction)");
  it.todo("should keep a block pattern stable across a generation (still life)");
});

